#include <bits/stdc++.h>
using namespace std;
int a[100101], b[100101];
int main() {
	long long n, m, l, r, mid, ans = 0;
	cin >> n >> m;
	for (int i = 0; i < n; i++) {
		cin >> a[i];
	}
	for (int i = 0; i < m; i++) {
		cin >> b[i];
	}
	sort(a, a + n);
	
	for (int i = 0; i < m; i++) {
			l = 0;
			r = n;
		while (l < r) {
			mid = (r + l) / 2;
			if (a[mid] <= b[i]) {
				l = mid + 1;
			} else {
				r = mid;
			}
		}
		if (b[i] <= a[0]) {
			ans += a[0] - b[i];
		} else {
			ans += min(abs(a[l - 1] - b[i]), abs(a[l] - b[i]));
		}
	}
	cout << ans;
	return 0;
}
